// SPDX-License-Identifier: MIT
pragma solidity ^0.8.13;

contract SimpleLoop{
    uint public result;
    function expensivePure(uint256 n) public pure returns(uint256){
        uint256 sum =0;
        for(uint256 i = 0; i <= n; i++)
        {
            sum += i;
        }
        return sum;
    }
    function callPureInternally()public{
        result = expensivePure(1000);
    }
}

